import type { FuncCatKey, FuncTaxonomyNode } from "~~/shared/types"

export const FUNC_TAXONOMY: FuncTaxonomyNode[] = [
  {
    key: "workTask",
    l1: [
      { key: "systemDesign", l2: ["reqAnalysis", "funcDesign", "archDesign"] },
      { key: "softDev", l2: ["frontend", "backend", "devops"] },
      { key: "testing", l2: ["unitTest", "intTest", "perfTest"] },
    ],
  },
  {
    key: "business",
    l1: [
      { key: "network", l2: ["http", "grpc", "mqtt"] },
      { key: "embedded", l2: ["rtos", "firmware", "drivers"] },
      { key: "cloud", l2: ["aws", "azure", "k8s"] },
    ],
  },
  {
    key: "tools",
    l1: [
      { key: "docs", l2: ["markdown", "pdf", "wiki"] },
      { key: "data", l2: ["csv", "sql", "viz"] },
      { key: "vcs", l2: ["git", "pr", "cicd"] },
    ],
  },
]

export const FUNC_CAT_COLORS: Record<FuncCatKey, string> = {
  workTask: "oklch(62% 0.18 255)",
  business: "oklch(62% 0.18 145)",
  tools: "oklch(62% 0.18 55)",
}

import { sql } from "drizzle-orm";
import {
  check,
  index,
  pgEnum,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
} from "drizzle-orm/pg-core";

import { users } from "./auth";
import { extensions, officialTierEnum, productLines } from "./extension";

export const approvalStatusEnum = pgEnum("approval_status", [
  "pending",
  "approved",
  "rejected",
  "withdrawn",
]);

export const approvalRequests = pgTable(
  "approval_requests",
  {
    id: text().primaryKey(),
    extensionId: text()
      .notNull()
      .references(() => extensions.id, { onDelete: "cascade" }),
    requestedTier: officialTierEnum().notNull(),
    // Snapshot of the functional subCat at submission time. Source of truth is
    // FUNC_TAXONOMY in shared/taxonomy.ts; validated against the flattened l1
    // key set at the validator layer.
    subCat: text().notNull(),
    // Product line snapshot — required iff requestedTier='productLine'.
    // RESTRICT on delete keeps the audit trail honest: a product line cannot
    // disappear while requests still reference it.
    productLineId: text().references(() => productLines.id, {
      onDelete: "restrict",
    }),
    requestedByUserId: text()
      .notNull()
      .references(() => users.id, { onDelete: "cascade" }),
    reason: text(),
    status: approvalStatusEnum().notNull().default("pending"),
    decidedByUserId: text().references(() => users.id, {
      onDelete: "set null",
    }),
    decidedAt: timestamp({ withTimezone: true }),
    reviewerNote: text(),
    createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
    updatedAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
  },
  (t) => [
    // Reviewer queue: pending rows in a given cell, ordered by createdAt.
    // productLineId trails so company-tier rows (productLineId IS NULL) still
    // collapse onto the same prefix; productLine-tier scans use the full key.
    index("idx_approval_status_cell").on(
      t.status,
      t.subCat,
      t.requestedTier,
      t.productLineId,
    ),
    // Publisher "my requests" view and the at-most-one-pending guard.
    index("idx_approval_ext_status").on(t.extensionId, t.status),
    // Shape invariant: productLineId is present iff requestedTier='productLine'.
    check(
      "approval_requests_pl_shape_chk",
      sql`(requested_tier = 'productLine' AND product_line_id IS NOT NULL)
        OR (requested_tier = 'company' AND product_line_id IS NULL)`,
    ),
  ],
);

export const approvalReviewers = pgTable(
  "approval_reviewers",
  {
    id: text().primaryKey(),
    tier: officialTierEnum().notNull(),
    // Same FUNC_TAXONOMY l1 key as approvalRequests.subCat — text rather
    // than enum so adding a taxonomy leaf doesn't require a migration.
    subCat: text().notNull(),
    // Product line this reviewer is scoped to. Required iff tier='productLine',
    // null when tier='company'. CHECK enforces the shape; the unique behaviour
    // for each tier is expressed below as two partial indexes.
    productLineId: text().references(() => productLines.id, {
      onDelete: "restrict",
    }),
    userId: text()
      .notNull()
      .references(() => users.id, { onDelete: "cascade" }),
    createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
  },
  (t) => [
    // Tier-aware uniqueness. ProductLine cells include productLineId in the
    // key; company cells do not. Two partial indexes are clearer than relying
    // on NULLS NOT DISTINCT and let each tier's arity stand on its own.
    uniqueIndex("approval_reviewers_pl_cell_user_uq")
      .on(t.tier, t.subCat, t.productLineId, t.userId)
      .where(sql`tier = 'productLine'`),
    uniqueIndex("approval_reviewers_co_cell_user_uq")
      .on(t.tier, t.subCat, t.userId)
      .where(sql`tier = 'company'`),
    index("idx_approval_reviewers_cell").on(
      t.tier,
      t.subCat,
      t.productLineId,
    ),
    // Shape invariant: productLineId is present iff tier='productLine'.
    check(
      "approval_reviewers_pl_shape_chk",
      sql`(tier = 'productLine' AND product_line_id IS NOT NULL)
        OR (tier = 'company' AND product_line_id IS NULL)`,
    ),
  ],
);

import { betterAuth } from "better-auth"
import { drizzleAdapter } from "better-auth/adapters/drizzle"
import { createError, getRequestHeaders, type H3Event } from "h3"

import type { OfficialTier } from "~~/shared/approvals/state"

import {
  isCompanyAdminForSubCat,
  isSuperAdmin,
} from "~~/server/repositories/reviewers"
import {
  accounts,
  sessions,
  users,
  verifications,
} from "~~/shared/db/schema/auth"

import { useDb } from "./db"

function makeAuth() {
  const db = useDb()
  return betterAuth({
    database: drizzleAdapter(db, {
      provider: "pg",
      schema: {
        user: users,
        session: sessions,
        account: accounts,
        verification: verifications,
      },
    }),
    emailAndPassword: { enabled: true },
    user: {
      additionalFields: {
        locale: {
          type: "string",
          required: false,
          defaultValue: "en",
          input: false,
        },
        themePreference: {
          type: "string",
          required: false,
          defaultValue: "ivory",
          input: false,
        },
        defaultDeptId: {
          type: "string",
          required: false,
          input: false,
        },
      },
    },
  })
}

type AuthInstance = ReturnType<typeof makeAuth>

let _auth: AuthInstance | undefined

export function useAuthServer(): AuthInstance {
  if (!_auth) _auth = makeAuth()
  return _auth
}

type SessionPayload = Awaited<
  ReturnType<AuthInstance["api"]["getSession"]>
>
export type SessionUser = NonNullable<SessionPayload>["user"]

function toFetchHeaders(raw: Record<string, string | string[] | undefined>): Headers {
  const headers = new Headers()
  for (const [key, value] of Object.entries(raw)) {
    if (value === undefined) continue
    headers.append(key, Array.isArray(value) ? value.join(", ") : value)
  }
  return headers
}

export async function getSessionUser(event: H3Event): Promise<SessionUser | null> {
  const auth = useAuthServer()
  const session = await auth.api.getSession({
    headers: toFetchHeaders(getRequestHeaders(event)),
  })
  return session?.user ?? null
}

export async function requireUser(event: H3Event): Promise<SessionUser> {
  const user = await getSessionUser(event)
  if (!user) {
    throw createError({ statusCode: 401, statusMessage: "Unauthenticated" })
  }
  return user
}

// Super-admin gate for the reviewer-matrix admin surface. Returns the
// session user when they hold any membership with role='superAdmin';
// throws 401 when unauthenticated and 403 otherwise. The membership
// lookup goes through the reviewers repo so the policy lives in one
// place — see `server/repositories/reviewers.ts`.
export async function requireSuperAdmin(event: H3Event): Promise<SessionUser> {
  const user = await requireUser(event)
  if (!(await isSuperAdmin(useDb(), user.id))) {
    throw createError({ statusCode: 403, statusMessage: "Forbidden" })
  }
  return user
}

// Cell-aware authorisation for matrix edits. Encodes the delegation rule
// from ADR-0001 (2026-06-08 addendum):
//   - super-admins can edit every cell;
//   - company-tier admins of subCat X may manage productLine cells of
//     subCat X (any productLine);
//   - company-tier cells stay super-admin-only.
// Callers pass the cell coordinates explicitly — for `unassign`, load the
// target row first so the gate authorises against that row's coordinates
// rather than the caller's request body.
export async function requireCellAdmin(
  event: H3Event,
  cell: { tier: OfficialTier; subCat: string; productLineId: string | null },
): Promise<SessionUser> {
  const user = await requireUser(event)
  const db = useDb()
  if (await isSuperAdmin(db, user.id)) return user
  if (
    cell.tier === "productLine" &&
    (await isCompanyAdminForSubCat(db, user.id, cell.subCat))
  ) {
    return user
  }
  throw createError({ statusCode: 403, statusMessage: "not_authorized" })
}

import { and, asc, eq, isNull } from "drizzle-orm"

import type { OfficialTier } from "~~/shared/approvals/state"
import {
  approvalReviewers,
  memberships,
  users,
} from "~~/shared/db/schema"

import type { Transactable } from "./types"

// `approval_reviewers` table accessor. Backs the reviewer matrix:
// (tier × subCat × productLineId?) → list of users assigned to decide on
// that cell. ProductLineId participates only for the `productLine` tier;
// the DB CHECK constraint enforces the iff-rule. Also exposes the
// super-admin lookup and the company-admin-for-subCat helper used by the
// delegated matrix-edit gate.

export type { OfficialTier }

export interface ReviewerRow {
  id: string
  tier: OfficialTier
  subCat: string
  productLineId: string | null
  userId: string
  userEmail: string
  userName: string | null
  createdAt: Date
}

export interface InsertReviewerRow {
  id: string
  tier: OfficialTier
  subCat: string
  productLineId: string | null
  userId: string
}

export interface ReviewerCell {
  tier: OfficialTier
  subCat: string
  productLineId: string | null
}

// Full matrix view, joined with `users` so the matrix UI can render
// reviewer chips with a recognisable label without an extra round-trip.
// productLineId sorts NULLS FIRST so company-tier rows precede the
// productLine grid in iteration order.
export async function listMatrix(db: Transactable): Promise<ReviewerRow[]> {
  return db
    .select({
      id: approvalReviewers.id,
      tier: approvalReviewers.tier,
      subCat: approvalReviewers.subCat,
      productLineId: approvalReviewers.productLineId,
      userId: approvalReviewers.userId,
      userEmail: users.email,
      userName: users.name,
      createdAt: approvalReviewers.createdAt,
    })
    .from(approvalReviewers)
    .innerJoin(users, eq(users.id, approvalReviewers.userId))
    .orderBy(
      asc(approvalReviewers.tier),
      asc(approvalReviewers.subCat),
      asc(approvalReviewers.productLineId),
      asc(users.email),
    )
}

// Cells (tier × subCat × productLineId?) where the given user is assigned.
// Used by the orchestrator to drive `listPendingForCells` from `approvals.ts`.
export async function listCellsForUser(
  db: Transactable,
  userId: string,
): Promise<ReviewerCell[]> {
  return db
    .select({
      tier: approvalReviewers.tier,
      subCat: approvalReviewers.subCat,
      productLineId: approvalReviewers.productLineId,
    })
    .from(approvalReviewers)
    .where(eq(approvalReviewers.userId, userId))
}

// SubCats this user is a company-tier reviewer for. Drives the delegated
// matrix-edit gate: a company admin of subCat X can manage productLine
// reviewers for subCat X (and only X).
export async function listCompanySubCatsForUser(
  db: Transactable,
  userId: string,
): Promise<string[]> {
  const rows = await db
    .select({ subCat: approvalReviewers.subCat })
    .from(approvalReviewers)
    .where(
      and(
        eq(approvalReviewers.userId, userId),
        eq(approvalReviewers.tier, "company"),
      ),
    )
  return rows.map((r) => r.subCat)
}

// Cheap per-cell version of the above for endpoint authorisation paths.
export async function isCompanyAdminForSubCat(
  db: Transactable,
  userId: string,
  subCat: string,
): Promise<boolean> {
  const [row] = await db
    .select({ id: approvalReviewers.id })
    .from(approvalReviewers)
    .where(
      and(
        eq(approvalReviewers.userId, userId),
        eq(approvalReviewers.tier, "company"),
        eq(approvalReviewers.subCat, subCat),
      ),
    )
    .limit(1)
  return !!row
}

// Per-cell reviewer list — useful for the orchestrator's notification fan-out.
// For company tier the productLineId argument is ignored (and asserted null
// in callers); for productLine tier it must be supplied or the cell match is
// ambiguous.
export async function findReviewersFor(
  db: Transactable,
  tier: OfficialTier,
  subCat: string,
  productLineId: string | null,
): Promise<string[]> {
  const rows = await db
    .select({ userId: approvalReviewers.userId })
    .from(approvalReviewers)
    .where(
      and(
        eq(approvalReviewers.tier, tier),
        eq(approvalReviewers.subCat, subCat),
        productLineId === null
          ? isNull(approvalReviewers.productLineId)
          : eq(approvalReviewers.productLineId, productLineId),
      ),
    )
  return rows.map((r) => r.userId)
}

export async function insertReviewer(
  db: Transactable,
  row: InsertReviewerRow,
): Promise<void> {
  // No `target` on the conflict clause — the table now carries two partial
  // unique indexes (one per tier) and Drizzle can't synthesise a typed
  // target across both. The CHECK + partial uniques still de-dupe at the
  // DB layer; this just makes a duplicate insert a no-op instead of an error.
  await db.insert(approvalReviewers).values(row).onConflictDoNothing()
}

export async function deleteReviewer(
  db: Transactable,
  id: string,
): Promise<void> {
  await db.delete(approvalReviewers).where(eq(approvalReviewers.id, id))
}

// Single-row fetch used by the unassign endpoint so it can authorise
// against the row's tier/subCat (delegation rule) before deleting.
export async function findReviewerById(
  db: Transactable,
  id: string,
): Promise<ReviewerRow | null> {
  const [row] = await db
    .select({
      id: approvalReviewers.id,
      tier: approvalReviewers.tier,
      subCat: approvalReviewers.subCat,
      productLineId: approvalReviewers.productLineId,
      userId: approvalReviewers.userId,
      userEmail: users.email,
      userName: users.name,
      createdAt: approvalReviewers.createdAt,
    })
    .from(approvalReviewers)
    .innerJoin(users, eq(users.id, approvalReviewers.userId))
    .where(eq(approvalReviewers.id, id))
    .limit(1)
  return row ?? null
}

// Super-admin check. A user is a super-admin if any of their memberships
// carries the `superAdmin` role. Decoupled from a specific org so seeded
// super-admins keep their authority even when the default org is renamed.
export async function isSuperAdmin(
  db: Transactable,
  userId: string,
): Promise<boolean> {
  const [row] = await db
    .select({ id: memberships.id })
    .from(memberships)
    .where(
      and(
        eq(memberships.userId, userId),
        eq(memberships.role, "superAdmin"),
      ),
    )
    .limit(1)
  return !!row
}

import { sql } from "drizzle-orm";
import {
  bigint,
  boolean,
  check,
  customType,
  index,
  integer,
  jsonb,
  numeric,
  pgEnum,
  pgTable,
  primaryKey,
  text,
  timestamp,
  unique,
} from "drizzle-orm/pg-core";

import { users } from "./auth";
import { departments, organizations } from "./org";

// tsvector is a Postgres-native type; Drizzle doesn't ship a built-in helper.
// We declare it as a custom type so the ORM can reference it in WHERE clauses
// via sql``. It is GENERATED ALWAYS (read-only); never written by app code.
const tsvector = customType<{ data: string }>({
  dataType() { return "tsvector"; },
});

export const extensionCategoryEnum = pgEnum("extension_category", [
  "skills",
  "mcp",
  "slash",
  "plugins",
]);

export const extensionScopeEnum = pgEnum("extension_scope", [
  "personal",
  "org",
  "enterprise",
]);

export const extensionBadgeEnum = pgEnum("extension_badge", [
  "official",
  "popular",
  "new",
]);

// Official-tier approval outcome. Null = unofficial (the default for any
// publisher-uploaded extension). Owned by the approval workflow — app code
// outside server/utils/approvals.ts MUST NOT write this column directly.
export const officialTierEnum = pgEnum("extension_official_tier", [
  "productLine",
  "company",
]);

export const funcCatEnum = pgEnum("func_cat", [
  "workTask",
  "business",
  "tools",
]);

export const visibilityEnum = pgEnum("extension_visibility", [
  "draft",
  "published",
  "archived",
]);

export const versionStatusEnum = pgEnum("version_status", [
  "pending",
  "scanning",
  "ready",
  "rejected",
]);

export const fileScanStatusEnum = pgEnum("file_scan_status", [
  "pending",
  "clean",
  "flagged",
]);

// Product-line lookup table — bilingual labels, kebab-case ids
// (`wireless`, `datacom`, `terminals`, `cloud`). Seeded by migration 0009.
// Used as the third axis of the reviewer matrix for the productLine tier,
// and as the company-level "endorsing line" on extensions whose
// officialTier='productLine'. Editable as data, not code, so adding a line
// is a content migration rather than a release.
export const productLines = pgTable("product_lines", {
  id: text().primaryKey(),
  labelEn: text().notNull(),
  labelZh: text().notNull(),
  sortOrder: integer().notNull().default(0),
  createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
});

export const extensions = pgTable(
  "extensions",
  {
    id: text().primaryKey(),
    slug: text().notNull().unique(),
    category: extensionCategoryEnum().notNull(),
    badge: extensionBadgeEnum(),
    scope: extensionScopeEnum().notNull(),
    // Official-tier approval outcome. Null = unofficial. See approval.ts.
    officialTier: officialTierEnum(),
    // Endorsing product line — required iff officialTier='productLine',
    // null otherwise. CHECK constraint below enforces the shape; the
    // approval orchestrator is the only writer. ON DELETE RESTRICT matches
    // the iff-rule: SET NULL would still fail the CHECK for every
    // productLine-tier row, so RESTRICT just surfaces the real outcome.
    productLineId: text().references(() => productLines.id, {
      onDelete: "restrict",
    }),
    // funcCat/subCat are nullable — the redesigned publish wizard does not
    // collect them; admin curation can backfill or system defaults apply.
    funcCat: funcCatEnum(),
    subCat: text(),
    l2: text(),
    publisherUserId: text().references(() => users.id, {
      onDelete: "set null",
    }),
    // Tier revocation audit trail. Populated when a super-admin demotes
    // an Official extension back to Unofficial via the detail page
    // Revoke action. Cleared on the next approval — see the orchestrator
    // in server/utils/approvals.ts. ON DELETE SET NULL on the admin FK
    // so deleting an admin orphans the attribution rather than failing
    // the cascade.
    revokedAt: timestamp({ withTimezone: true }),
    revokedByUserId: text().references(() => users.id, {
      onDelete: "set null",
    }),
    revocationNote: text(),
    ownerOrgId: text()
      .notNull()
      .references(() => organizations.id, { onDelete: "cascade" }),
    deptId: text().references(() => departments.id, { onDelete: "set null" }),
    iconEmoji: text(),
    iconColor: text(),
    visibility: visibilityEnum().notNull().default("draft"),
    // Editorial flag — hand-curated. Surfaces a single extension on the home
    // hero. Coexists with `badge`: badge is a static editorial mark on the
    // card; `featured` is a transient "pick of the week" pointer.
    featured: boolean().notNull().default(false),
    // i18n columns
    name: text().notNull(),
    nameZh: text(),
    tagline: text(),
    taglineZh: text(),
    description: text(),
    descriptionZh: text(),
    // Long-form markdown body for the detail page. Not duplicated to ZH yet —
    // most extensions will have an English README, with translations layered
    // on later if needed.
    readmeMd: text(),
    // metadata for detail page sidebar
    homepageUrl: text(),
    repoUrl: text(),
    licenseSpdx: text(),
    compatibilityJson: jsonb(),
    // Permissions captured during publish (network/files/runtime/data, etc.).
    // Surfaced on the detail page so users see what the extension wants.
    permissions: jsonb().notNull().default({}),
    // denormalized counters (updated by jobs)
    downloadsCount: integer().notNull().default(0),
    starsAvg: numeric({ precision: 2, scale: 1 }).notNull().default("0.0"),
    ratingsCount: integer().notNull().default(0),
    publishedAt: timestamp({ withTimezone: true }),
    createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
    updatedAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
    searchVector: tsvector("search_vector"),
  },
  (t) => [
    index("idx_ext_category").on(t.category),
    index("idx_ext_scope").on(t.scope),
    index("idx_ext_official_tier").on(t.officialTier),
    index("idx_ext_product_line").on(t.productLineId),
    index("idx_ext_func_sub_l2").on(t.funcCat, t.subCat, t.l2),
    index("idx_ext_dept_path").using(
      "btree",
      sql`${t.deptId} text_pattern_ops`,
    ),
    index("idx_ext_visibility").on(t.visibility),
    index("idx_ext_downloads").on(sql`${t.downloadsCount} DESC`),
    index("idx_ext_stars").on(sql`${t.starsAvg} DESC`),
    index("idx_ext_featured_published").on(
      t.featured,
      sql`${t.publishedAt} DESC`,
    ),
    // Shape invariant: productLineId is present iff officialTier='productLine'.
    // Mirrors the same rule on approval_requests and approval_reviewers.
    check(
      "extensions_pl_shape_chk",
      sql`official_tier IS NULL
        OR (official_tier = 'productLine' AND product_line_id IS NOT NULL)
        OR (official_tier = 'company' AND product_line_id IS NULL)`,
    ),
  ],
);

export const extensionVersions = pgTable(
  "extension_versions",
  {
    id: text().primaryKey(),
    extensionId: text()
      .notNull()
      .references(() => extensions.id, { onDelete: "cascade" }),
    version: text().notNull(), // semver
    changelog: text(),
    changelogZh: text(),
    manifestJson: jsonb(),
    // Logical reference to files.id; no FK constraint to avoid a circular FK
    // with files.extensionVersionId. App code keeps these consistent.
    bundleFileId: text(),
    status: versionStatusEnum().notNull().default("pending"),
    // Source method chosen during publish: zip (only one wired today), git, cli.
    // Stored as text rather than enum so adding methods doesn't require a migration.
    sourceMethod: text().notNull().default("zip"),
    sourceMeta: jsonb().notNull().default({}),
    publishedAt: timestamp({ withTimezone: true }),
    createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
  },
  (t) => [unique("ext_version_unique").on(t.extensionId, t.version)],
);

export const files = pgTable("files", {
  id: text().primaryKey(),
  extensionVersionId: text().references(() => extensionVersions.id, {
    onDelete: "set null",
  }),
  r2Key: text().notNull(),
  size: bigint({ mode: "bigint" }).notNull(),
  checksumSha256: text().notNull(),
  mimeType: text(),
  scanStatus: fileScanStatusEnum().notNull().default("pending"),
  scanReport: jsonb(),
  createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
});

export const tags = pgTable("tags", {
  id: text().primaryKey(), // tag key, e.g. "real-time"
  labelEn: text().notNull(),
  labelZh: text().notNull(),
});

export const extensionTags = pgTable(
  "extension_tags",
  {
    extensionId: text()
      .notNull()
      .references(() => extensions.id, { onDelete: "cascade" }),
    tagId: text()
      .notNull()
      .references(() => tags.id, { onDelete: "cascade" }),
  },
  (t) => [
    primaryKey({ columns: [t.extensionId, t.tagId] }),
    index("idx_extension_tags_tag_ext").on(t.tagId, t.extensionId),
  ],
);

