import * as approvalsRepo from "~~/server/repositories/approvals"
import * as extensionsRepo from "~~/server/repositories/extensions"
import * as reviewersRepo from "~~/server/repositories/reviewers"
import {
  decideApprovalOutcome,
  decideWithdrawOutcome,
  type ApprovalAction,
  type OfficialTier,
} from "~~/shared/approvals/state"

import { useDb } from "./db"
import { safeSend } from "./inngest"

// Orchestrators over the approvals/reviewers/extensions repositories. Pure
// transitions live in `shared/approvals/state.ts`; this file loads rows,
// opens transactions, fires Inngest events, and maps domain errors to
// HTTP-shaped codes the endpoints translate.

export type ApprovalErrorCode =
  | "extension_not_found"
  | "not_publisher_owner"
  | "extension_not_published"
  | "request_not_found"
  | "request_not_pending"
  | "duplicate_pending_request"
  | "not_reviewer"
  | "not_requester"
  | "missing_product_line"
  | "unexpected_product_line"
  | "extension_not_official"

export class ApprovalError extends Error {
  readonly code: ApprovalErrorCode
  constructor(code: ApprovalErrorCode) {
    super(code)
    this.code = code
    this.name = "ApprovalError"
  }
}

export interface SubmitParams {
  extensionId: string
  requestedTier: OfficialTier
  subCat: string
  productLineId: string | null
  userId: string
  reason: string | undefined
}

export async function submitRequest(
  params: SubmitParams,
): Promise<approvalsRepo.ApprovalRequestRow> {
  // Shape rule mirrors the DB CHECK: productLineId is present iff the
  // requested tier is `productLine`. Surfacing both error codes lets the
  // endpoint give a precise message instead of bouncing the raw 23514.
  if (params.requestedTier === "productLine" && !params.productLineId) {
    throw new ApprovalError("missing_product_line")
  }
  if (params.requestedTier === "company" && params.productLineId) {
    throw new ApprovalError("unexpected_product_line")
  }

  const db = useDb()

  const ext = await extensionsRepo.findById(db, params.extensionId)
  if (!ext) throw new ApprovalError("extension_not_found")
  if (ext.publisherUserId !== params.userId) {
    throw new ApprovalError("not_publisher_owner")
  }
  if (ext.visibility !== "published") {
    throw new ApprovalError("extension_not_published")
  }

  const row = await db.transaction(async (tx) => {
    // Re-check inside the transaction — race window between the visibility
    // load above and the insert below would otherwise let a duplicate slip
    // through. PG isolation is `read committed` so the second check still
    // sees a concurrent insert that already committed.
    const existing = await approvalsRepo.findPendingByExtension(
      tx,
      params.extensionId,
    )
    if (existing) throw new ApprovalError("duplicate_pending_request")

    return approvalsRepo.insertRequest(tx, {
      id: crypto.randomUUID(),
      extensionId: params.extensionId,
      requestedTier: params.requestedTier,
      subCat: params.subCat,
      productLineId: params.productLineId,
      requestedByUserId: params.userId,
      reason: params.reason ?? null,
    })
  })

  // Best-effort: the request row is the source of truth and is already
  // visible in the reviewer queue. A transient Inngest outage (or, in dev,
  // a missing `inngest-cli dev` process) must not fail the user's submit
  // after the row has been committed.
  await safeSend({
    name: "extension/approval.requested",
    data: {
      requestId: row.id,
      extensionId: row.extensionId,
      requestedTier: row.requestedTier,
      subCat: row.subCat,
      productLineId: row.productLineId,
      requesterUserId: row.requestedByUserId,
    },
  })

  return row
}

export interface DecideParams {
  requestId: string
  action: ApprovalAction
  reviewerUserId: string
}

export async function decideRequest(
  params: DecideParams,
): Promise<approvalsRepo.ApprovalRequestRow> {
  const db = useDb()

  const current = await approvalsRepo.findById(db, params.requestId)
  if (!current) throw new ApprovalError("request_not_found")
  if (current.status !== "pending") {
    throw new ApprovalError("request_not_pending")
  }

  // Super-admins can decide on any cell; otherwise the reviewer must be
  // assigned to the exact (requestedTier, subCat, productLineId?) cell this
  // request was filed against. Tier mismatches don't leak across cells.
  const allowed =
    (await reviewersRepo.isSuperAdmin(db, params.reviewerUserId)) ||
    (await approvalsRepo.isReviewerForCell(
      db,
      params.reviewerUserId,
      current.requestedTier,
      current.subCat,
      current.productLineId,
    ))
  if (!allowed) throw new ApprovalError("not_reviewer")

  const outcome = decideApprovalOutcome({
    current: {
      status: current.status,
      requestedTier: current.requestedTier,
    },
    action: params.action,
    reviewerUserId: params.reviewerUserId,
    now: new Date(),
  })

  // Optimistic locking lives inside the repository's UPDATE — if a second
  // reviewer decided between the pre-check above and this transaction, the
  // affected row count comes back zero and we surface the race as
  // `request_not_pending`.
  await db.transaction(async (tx) => {
    const updated = await approvalsRepo.applyDecision(
      tx,
      params.requestId,
      outcome.request,
    )
    if (updated === 0) throw new ApprovalError("request_not_pending")
    if (outcome.extension) {
      await approvalsRepo.setExtensionOfficialTier(
        tx,
        current.extensionId,
        outcome.extension.officialTier,
        current.productLineId,
      )
    }
  })

  const updated = await approvalsRepo.findById(db, params.requestId)
  if (!updated) throw new Error("approval request vanished mid-decide")

  // Best-effort notification after commit; see submitRequest for rationale.
  await safeSend({
    name: "extension/approval.decided",
    data: {
      requestId: updated.id,
      extensionId: updated.extensionId,
      decision: outcome.request.status,
      decidedByUserId: params.reviewerUserId,
    },
  })

  return updated
}

export interface WithdrawParams {
  requestId: string
  userId: string
}

export async function withdrawRequest(
  params: WithdrawParams,
): Promise<approvalsRepo.ApprovalRequestRow> {
  const db = useDb()

  const current = await approvalsRepo.findById(db, params.requestId)
  if (!current) throw new ApprovalError("request_not_found")
  if (current.requestedByUserId !== params.userId) {
    throw new ApprovalError("not_requester")
  }
  if (current.status !== "pending") {
    throw new ApprovalError("request_not_pending")
  }

  const outcome = decideWithdrawOutcome({
    current: { status: current.status },
    now: new Date(),
  })
  const affected = await approvalsRepo.applyWithdraw(
    db,
    params.requestId,
    outcome.request.decidedAt,
  )
  if (affected === 0) throw new ApprovalError("request_not_pending")

  const updated = await approvalsRepo.findById(db, params.requestId)
  if (!updated) throw new Error("approval request vanished mid-withdraw")
  return updated
}

export interface RevokeTierParams {
  extensionId: string
  superAdminUserId: string
  note: string
}

export interface RevokeTierResult {
  extensionId: string
  revokedAt: Date
}

// Super-admin Revoke action from the detail page. Loads the extension,
// pre-checks that it's actually Official, then atomically clears tier +
// productLineId and writes the audit trio. The DB-level WHERE clause in
// applyRevocation re-checks officialTier IS NOT NULL so a concurrent
// revoke / re-approval loses the race and surfaces as
// `extension_not_official` rather than silently clobbering the row.
// Caller is expected to already be a super-admin (gated at the endpoint
// via requireSuperAdmin) — we don't re-check here for the same reason the
// reviewer-assign endpoint doesn't re-check its gate.
export async function revokeTier(
  params: RevokeTierParams,
): Promise<RevokeTierResult> {
  const db = useDb()
  const ext = await extensionsRepo.findById(db, params.extensionId)
  if (!ext) throw new ApprovalError("extension_not_found")
  if (!ext.officialTier) throw new ApprovalError("extension_not_official")

  const revokedAt = new Date()
  const affected = await db.transaction(async (tx) => {
    return approvalsRepo.applyRevocation(tx, params.extensionId, {
      revokedAt,
      revokedByUserId: params.superAdminUserId,
      revocationNote: params.note,
    })
  })
  if (affected === 0) throw new ApprovalError("extension_not_official")

  // Best-effort notification after commit; see submitRequest for rationale.
  await safeSend({
    name: "extension/tier.revoked",
    data: {
      extensionId: params.extensionId,
      revokedByUserId: params.superAdminUserId,
      revokedAt: revokedAt.toISOString(),
      note: params.note,
    },
  })

  return { extensionId: params.extensionId, revokedAt }
}

export interface ReviewerQueueFilters {
  tier?: OfficialTier
  subCat?: string
  productLineId?: string
}

// Reviewer queue — pending requests in any cell this user covers. Returns
// an empty array when the user has no cell assignments (and is not a
// super-admin); super-admins see the whole pending queue.
//
// Optional `filters` narrow the queue without changing the trust model:
// the cells are computed first (so a reviewer never queries outside their
// own assignment), then filtered, then handed to listPendingForCells. A
// filter that excludes every cell yields an empty `cells` array, which
// listPendingForCells short-circuits to [] — no special-case branch.
export async function listReviewerQueue(
  userId: string,
  filters: ReviewerQueueFilters = {},
): Promise<approvalsRepo.ApprovalRequestRow[]> {
  const db = useDb()
  let cells: Array<{
    tier: OfficialTier
    subCat: string
    productLineId: string | null
  }>
  if (await reviewersRepo.isSuperAdmin(db, userId)) {
    // Treat super-admin as "assigned to every cell". Pulled from the matrix
    // verbatim so an empty matrix still surfaces no rows — better than a
    // silent firehose. Productline IS NULL is encoded as the literal '∅' in
    // the dedup key so a (company, cloud, null) cell doesn't collapse onto
    // (productLine, cloud, '') by accident.
    cells = await reviewersRepo
      .listMatrix(db)
      .then((rows) =>
        Array.from(
          new Set(
            rows.map((r) => `${r.tier}:${r.subCat}:${r.productLineId ?? "∅"}`),
          ),
        ).map((k) => {
          const [tier, subCat, pl] = k.split(":") as [OfficialTier, string, string]
          return {
            tier,
            subCat,
            productLineId: pl === "∅" ? null : pl,
          }
        }),
      )
  } else {
    cells = await reviewersRepo.listCellsForUser(db, userId)
  }

  const narrowed = cells.filter((c) => {
    if (filters.tier && c.tier !== filters.tier) return false
    if (filters.subCat && c.subCat !== filters.subCat) return false
    if (filters.productLineId && c.productLineId !== filters.productLineId)
      return false
    return true
  })
  return approvalsRepo.listPendingForCells(db, narrowed)
}

export async function listPublisherRequests(
  userId: string,
): Promise<approvalsRepo.ApprovalRequestRow[]> {
  return approvalsRepo.listForPublisher(useDb(), userId)
}

import { and, desc, eq, inArray, isNull, sql } from "drizzle-orm"

import type {
  ApprovalStatus,
  OfficialTier,
} from "~~/shared/approvals/state"
import {
  approvalRequests,
  approvalReviewers,
  extensions,
} from "~~/shared/db/schema"

import type { Transactable } from "./types"

// `approval_requests` table accessor. Used by the approval orchestrator to
// drive the publisher submit / reviewer decide / publisher withdraw flow.
// `ApprovalStatus` and `OfficialTier` are re-exported so callers that
// already depend on the repository module don't need a second import.

export type { ApprovalStatus, OfficialTier }

export interface ApprovalRequestRow {
  id: string
  extensionId: string
  requestedTier: OfficialTier
  subCat: string
  productLineId: string | null
  requestedByUserId: string
  reason: string | null
  status: ApprovalStatus
  decidedByUserId: string | null
  decidedAt: Date | null
  reviewerNote: string | null
  createdAt: Date
  updatedAt: Date
}

const fullSelect = {
  id: approvalRequests.id,
  extensionId: approvalRequests.extensionId,
  requestedTier: approvalRequests.requestedTier,
  subCat: approvalRequests.subCat,
  productLineId: approvalRequests.productLineId,
  requestedByUserId: approvalRequests.requestedByUserId,
  reason: approvalRequests.reason,
  status: approvalRequests.status,
  decidedByUserId: approvalRequests.decidedByUserId,
  decidedAt: approvalRequests.decidedAt,
  reviewerNote: approvalRequests.reviewerNote,
  createdAt: approvalRequests.createdAt,
  updatedAt: approvalRequests.updatedAt,
}

export interface InsertApprovalRequest {
  id: string
  extensionId: string
  requestedTier: OfficialTier
  subCat: string
  productLineId: string | null
  requestedByUserId: string
  reason: string | null
}

export async function insertRequest(
  db: Transactable,
  row: InsertApprovalRequest,
): Promise<ApprovalRequestRow> {
  const [created] = await db
    .insert(approvalRequests)
    .values(row)
    .returning(fullSelect)
  if (!created) throw new Error("approval request insert vanished")
  return created
}

export async function findById(
  db: Transactable,
  id: string,
): Promise<ApprovalRequestRow | null> {
  const [row] = await db
    .select(fullSelect)
    .from(approvalRequests)
    .where(eq(approvalRequests.id, id))
    .limit(1)
  return row ?? null
}

// Bulk variant of `findPendingByExtension` for the publisher dashboard —
// the listing already loads many extensions, so we fan in a single query
// rather than N round-trips and return a Map<extId, pendingRequest>.
export async function findPendingForExtensions(
  db: Transactable,
  extensionIds: string[],
): Promise<Map<string, ApprovalRequestRow>> {
  if (extensionIds.length === 0) return new Map()
  const rows = await db
    .select(fullSelect)
    .from(approvalRequests)
    .where(
      and(
        inArray(approvalRequests.extensionId, extensionIds),
        eq(approvalRequests.status, "pending"),
      ),
    )
  return new Map(rows.map((r) => [r.extensionId, r]))
}

// Used by the at-most-one-pending guard in the submit orchestrator.
export async function findPendingByExtension(
  db: Transactable,
  extensionId: string,
): Promise<ApprovalRequestRow | null> {
  const [row] = await db
    .select(fullSelect)
    .from(approvalRequests)
    .where(
      and(
        eq(approvalRequests.extensionId, extensionId),
        eq(approvalRequests.status, "pending"),
      ),
    )
    .limit(1)
  return row ?? null
}

// Publisher's "my requests" view.
export async function listForPublisher(
  db: Transactable,
  userId: string,
): Promise<ApprovalRequestRow[]> {
  return db
    .select(fullSelect)
    .from(approvalRequests)
    .where(eq(approvalRequests.requestedByUserId, userId))
    .orderBy(desc(approvalRequests.createdAt))
}

// Reviewer's queue — pending requests in any (tier, subCat, productLineId?)
// cell that the reviewer is assigned to. Implemented as a single query
// against the cells the reviewer covers; the orchestrator pre-computes the
// cell list from `approval_reviewers` to keep this method driver-portable
// (no LATERAL). ProductLineId is matched IS NULL for company-tier cells
// and = productLineId for productLine-tier cells, so a company-tier
// reviewer never sees productLine-tier requests and vice versa.
export async function listPendingForCells(
  db: Transactable,
  cells: Array<{ tier: OfficialTier; subCat: string; productLineId: string | null }>,
): Promise<ApprovalRequestRow[]> {
  if (cells.length === 0) return []
  const cellMatches = cells.map((c) =>
    and(
      eq(approvalRequests.requestedTier, c.tier),
      eq(approvalRequests.subCat, c.subCat),
      c.productLineId === null
        ? isNull(approvalRequests.productLineId)
        : eq(approvalRequests.productLineId, c.productLineId),
    ),
  )
  return db
    .select(fullSelect)
    .from(approvalRequests)
    .where(
      and(
        eq(approvalRequests.status, "pending"),
        sql`(${sql.join(cellMatches, sql` OR `)})`,
      ),
    )
    .orderBy(desc(approvalRequests.createdAt))
}

export interface DecidePatch {
  status: "approved" | "rejected"
  decidedByUserId: string
  decidedAt: Date
  reviewerNote: string | null
}

// Optimistic-locking variant: only updates a request that's still pending.
// Returns the number of affected rows so the orchestrator can detect a
// race (a second reviewer that committed between the orchestrator's
// pre-check and this UPDATE) and surface it as `request_not_pending`.
export async function applyDecision(
  db: Transactable,
  id: string,
  patch: DecidePatch,
): Promise<number> {
  const updated = await db
    .update(approvalRequests)
    .set({ ...patch, updatedAt: new Date() })
    .where(
      and(
        eq(approvalRequests.id, id),
        eq(approvalRequests.status, "pending"),
      ),
    )
    .returning({ id: approvalRequests.id })
  return updated.length
}

// Same optimistic-locking shape as `applyDecision` — only a pending
// request can be withdrawn, and the affected row count tells the caller
// whether the transition actually fired.
export async function applyWithdraw(
  db: Transactable,
  id: string,
  decidedAt: Date,
): Promise<number> {
  const updated = await db
    .update(approvalRequests)
    .set({ status: "withdrawn", decidedAt, updatedAt: new Date() })
    .where(
      and(
        eq(approvalRequests.id, id),
        eq(approvalRequests.status, "pending"),
      ),
    )
    .returning({ id: approvalRequests.id })
  return updated.length
}

// Companion mutator for the approve path — stamps `officialTier` and the
// matching `productLineId` (null for company tier) on the parent extension.
// Lives here (rather than in `extensions.ts`) because the approval
// orchestrator is the only legitimate writer; keeping the call adjacent to
// the request mutation makes that intent obvious. The DB CHECK enforces
// productLineId is non-null iff tier='productLine', so a bad pair from a
// caller is rejected at the boundary. Also clears the revocation audit
// fields in the same UPDATE — the invariant is "you're either currently
// Official with no pending revocation explanation, or Unofficial".
export async function setExtensionOfficialTier(
  db: Transactable,
  extensionId: string,
  tier: OfficialTier,
  productLineId: string | null,
): Promise<void> {
  await db
    .update(extensions)
    .set({
      officialTier: tier,
      productLineId,
      revokedAt: null,
      revokedByUserId: null,
      revocationNote: null,
      updatedAt: new Date(),
    })
    .where(eq(extensions.id, extensionId))
}

// Companion mutator for the revoke path — atomically clears
// `officialTier` and `productLineId` while writing the audit trio
// (`revokedAt`, `revokedByUserId`, `revocationNote`). The orchestrator's
// pre-check already confirmed the row was Official; this method's
// returned affected-row count is the race-safe equivalent of a CAS,
// surfacing "someone else already revoked / re-approved" as a 0.
export interface RevocationPatch {
  revokedAt: Date
  revokedByUserId: string
  revocationNote: string
}
export async function applyRevocation(
  db: Transactable,
  extensionId: string,
  patch: RevocationPatch,
): Promise<number> {
  const updated = await db
    .update(extensions)
    .set({
      officialTier: null,
      productLineId: null,
      revokedAt: patch.revokedAt,
      revokedByUserId: patch.revokedByUserId,
      revocationNote: patch.revocationNote,
      updatedAt: new Date(),
    })
    .where(
      and(
        eq(extensions.id, extensionId),
        sql`${extensions.officialTier} IS NOT NULL`,
      ),
    )
    .returning({ id: extensions.id })
  return updated.length
}

// Bulk lookup of `officialTier` for a set of extensions — used by the
// publisher dashboard to render the per-row badge alongside any pending
// requests in one round-trip.
export async function findTiersForExtensions(
  db: Transactable,
  extensionIds: string[],
): Promise<Map<string, OfficialTier | null>> {
  if (extensionIds.length === 0) return new Map()
  const rows = await db
    .select({ id: extensions.id, officialTier: extensions.officialTier })
    .from(extensions)
    .where(inArray(extensions.id, extensionIds))
  return new Map(rows.map((r) => [r.id, r.officialTier ?? null]))
}

// Used by guards in `decide.post.ts` — confirms a user is assigned to the
// cell that the request originated from. Super-admins are handled in the
// orchestrator (a separate join) so this stays a pure reviewer check.
// ProductLineId is null for company-tier requests and the cell match must
// be exact on that NULLness to keep tiers from leaking into one another.
export async function isReviewerForCell(
  db: Transactable,
  userId: string,
  tier: OfficialTier,
  subCat: string,
  productLineId: string | null,
): Promise<boolean> {
  const [row] = await db
    .select({ id: approvalReviewers.id })
    .from(approvalReviewers)
    .where(
      and(
        eq(approvalReviewers.userId, userId),
        eq(approvalReviewers.tier, tier),
        eq(approvalReviewers.subCat, subCat),
        productLineId === null
          ? isNull(approvalReviewers.productLineId)
          : eq(approvalReviewers.productLineId, productLineId),
      ),
    )
    .limit(1)
  return !!row
}

import {
  isSuperAdmin,
  listCompanySubCatsForUser,
  listMatrix,
} from "~~/server/repositories/reviewers"
import { listAllProductLines } from "~~/server/repositories/productLines"

// Returns the reviewer matrix plus per-cell `canEdit` annotations and the
// productLine list, so the admin UI can render the productLine grid and
// grey non-editable cells in one round-trip. The access gate widens from
// "super-admin only" to "super-admin OR any company-tier reviewer" — the
// non-super viewer sees the full read-only matrix and can only mutate
// productLine cells in their own subCats (see requireCellAdmin).
export default defineEventHandler(async (event) => {
  const user = await requireUser(event)
  const db = useDb()
  const [superAdmin, companySubCats] = await Promise.all([
    isSuperAdmin(db, user.id),
    listCompanySubCatsForUser(db, user.id),
  ])
  const isCompanyAdmin = companySubCats.length > 0
  if (!superAdmin && !isCompanyAdmin) {
    throw createError({ statusCode: 403, statusMessage: "Forbidden" })
  }

  const editableSubCats = new Set(companySubCats)
  const [reviewers, productLines] = await Promise.all([
    listMatrix(db),
    listAllProductLines(db),
  ])

  return {
    ok: true,
    productLines,
    reviewers: reviewers.map((r) => ({
      ...r,
      canEdit:
        superAdmin ||
        (r.tier === "productLine" && editableSubCats.has(r.subCat)),
    })),
    viewer: {
      isSuperAdmin: superAdmin,
      companySubCats,
    },
  }
})

import { insertReviewer } from "~~/server/repositories/reviewers"
import { AssignReviewerSchema } from "~~/shared/validators/approvals"

// Per-cell authorisation: super-admins anywhere, company admins of subCat X
// may assign productLine reviewers for subCat X (any productLine), and
// company-tier cells stay super-admin-only. The validator's iff-rule
// already guarantees productLineId is present iff tier='productLine'.
export default defineEventHandler(async (event) => {
  const body = await readValidatedBody(event, (raw) =>
    AssignReviewerSchema.parse(raw),
  )
  await requireCellAdmin(event, {
    tier: body.tier,
    subCat: body.subCat,
    productLineId: body.productLineId ?? null,
  })

  await insertReviewer(useDb(), {
    id: crypto.randomUUID(),
    tier: body.tier,
    subCat: body.subCat,
    productLineId: body.productLineId ?? null,
    userId: body.userId,
  })
  return { ok: true }
})

import {
  deleteReviewer,
  findReviewerById,
} from "~~/server/repositories/reviewers"
import { UnassignReviewerSchema } from "~~/shared/validators/approvals"

// Load the row first so the cell-aware gate authorises against the row's
// own (tier, subCat, productLineId), not against anything the caller
// supplies. Without this, a company admin of subCat X could uncover the
// id of a company-tier reviewer in any subCat by guessing — the request
// body alone can't tell us which cell the id belongs to.
export default defineEventHandler(async (event) => {
  const body = await readValidatedBody(event, (raw) =>
    UnassignReviewerSchema.parse(raw),
  )
  const row = await findReviewerById(useDb(), body.id)
  if (!row) {
    throw createError({ statusCode: 404, statusMessage: "reviewer_not_found" })
  }
  await requireCellAdmin(event, {
    tier: row.tier,
    subCat: row.subCat,
    productLineId: row.productLineId,
  })
  await deleteReviewer(useDb(), body.id)
  return { ok: true }
})

