        productLineId: null,
        categoryLevel: "all",
        categoryKey: "*",
        userEmail: "bob@example.com",
        userName: "Bob",
      })
    })

    it("is a no-op on identical cell+user conflict for productLine cells", async () => {
      await adminsRepo.insertAdmin(db, {
        id: "adm-1",
        extensionCategory: "skills",
        tier: "productLine",
        productLineId: "wireless",
        categoryLevel: "macro",
