import { eq, sql } from "drizzle-orm"
import { afterAll, beforeAll, beforeEach, describe, expect, it } from "vitest"

import * as approvalsRepo from "~~/server/repositories/approvals"
import * as adminsRepo from "~~/server/repositories/admins"
import {
  approvalAdmins,
  approvalRequests,
  extensions,
  organizations,
  users,
} from "~~/shared/db/schema"

import { setupDb, type TestDb } from "../helpers/db"

describe("approvals repository", () => {
  let db: TestDb
  let cleanup: () => Promise<void>

  beforeAll(async () => {
    const handle = await setupDb()
    db = handle.db
    cleanup = handle.cleanup

    await db.insert(organizations).values({
      id: "org-1",
      slug: "org-1",
      name: "Org One",
    })
    await db.insert(users).values([
      { id: "u-pub", email: "pub@example.com", name: "Pub", emailVerified: true },
      { id: "u-rev", email: "rev@example.com", name: "Rev", emailVerified: true },
      { id: "u-other", email: "other@example.com", name: "Other", emailVerified: true },
    ])
    await db.insert(extensions).values([
      {
        id: "ext-a",
        slug: "ext-a",
        category: "skills",
        scope: "personal",
        ownerOrgId: "org-1",
        publisherUserId: "u-pub",
        subCat: "softDev",
        l2: "backend",
        name: "Ext A",
        visibility: "published",
      },
      {
        id: "ext-b",
        slug: "ext-b",
        category: "skills",
        scope: "personal",
        ownerOrgId: "org-1",
        publisherUserId: "u-pub",
        subCat: "docs",
        name: "Ext B",
        visibility: "published",
      },
    ])
  })

  afterAll(async () => {
    await cleanup()
  })

  beforeEach(async () => {
    await db.delete(approvalRequests)
    await db.delete(approvalAdmins)
    // Reset officialTier between specs so the bulk-lookup test starts clean.
    // No `.where(...)` would also wipe everything but Drizzle requires the
    // clause; sql`1=1` is the standard "match every row" pattern.
    await db.update(extensions).set({ officialTier: null }).where(sql`1 = 1`)
  })

  describe("insertRequest + findById", () => {
    it("persists a pending request with snapshotted tier / category / l2 / subCat", async () => {
      const row = await approvalsRepo.insertRequest(db, {
        id: "req-1",
        extensionId: "ext-a",
        extensionCategory: "skills",
        requestedTier: "company",
        subCat: "softDev",
        l2: "backend",
        productLineId: null,
        requestedByUserId: "u-pub",
        reason: "Used by 5 teams.",
      })

      expect(row.status).toBe("pending")
      expect(row.requestedTier).toBe("company")
      expect(row.extensionCategory).toBe("skills")
      expect(row.subCat).toBe("softDev")
      expect(row.l2).toBe("backend")
      expect(row.reason).toBe("Used by 5 teams.")
      expect(row.decidedByUserId).toBeNull()
      expect(row.decidedAt).toBeNull()
      expect(row.reviewerNote).toBeNull()
      expect(row.createdAt).toBeInstanceOf(Date)
    })

    it("accepts l2=null for extensions without an l2 classification", async () => {
      const row = await approvalsRepo.insertRequest(db, {
        id: "req-2",
        extensionId: "ext-b",
        extensionCategory: "skills",
        requestedTier: "company",
        subCat: "docs",
        l2: null,
        productLineId: null,
        requestedByUserId: "u-pub",
        reason: null,
      })
      expect(row.l2).toBeNull()
    })
  })

  describe("findPendingByExtension", () => {
    it("returns the pending request when one exists", async () => {
      await approvalsRepo.insertRequest(db, {
        id: "req-1",
        extensionId: "ext-a",
        extensionCategory: "skills",
        requestedTier: "productLine",
        subCat: "softDev",
        l2: "backend",
        productLineId: "wireless",
        requestedByUserId: "u-pub",
        reason: null,
      })
      const found = await approvalsRepo.findPendingByExtension(db, "ext-a")
      expect(found?.id).toBe("req-1")
    })

    it("returns null when no pending request exists", async () => {
      expect(
        await approvalsRepo.findPendingByExtension(db, "ext-a"),
      ).toBeNull()
    })

    it("ignores withdrawn / approved / rejected requests", async () => {
      await approvalsRepo.insertRequest(db, {
        id: "req-1",
        extensionId: "ext-a",
        extensionCategory: "skills",
        requestedTier: "productLine",
        subCat: "softDev",
        l2: "backend",
        productLineId: "wireless",
        requestedByUserId: "u-pub",
        reason: null,
      })
      await approvalsRepo.applyWithdraw(db, "req-1", new Date())
      expect(
        await approvalsRepo.findPendingByExtension(db, "ext-a"),
      ).toBeNull()
    })
  })

  describe("listForPublisher", () => {
    it("returns the user's requests ordered by createdAt desc", async () => {
      await approvalsRepo.insertRequest(db, {
        id: "req-old",
        extensionId: "ext-a",
        extensionCategory: "skills",
        requestedTier: "productLine",
        subCat: "softDev",
        l2: "backend",
        productLineId: "wireless",
        requestedByUserId: "u-pub",
        reason: null,
      })
      // Spread createdAt by hand so the desc order is unambiguous regardless
      // of wall-clock resolution.
      await db
        .update(approvalRequests)
        .set({ createdAt: new Date("2026-06-01T10:00:00Z") })
        .where(eq(approvalRequests.id, "req-old"))

      await approvalsRepo.insertRequest(db, {
        id: "req-new",
        extensionId: "ext-b",
        extensionCategory: "skills",
        requestedTier: "company",
        subCat: "docs",
        l2: null,
        productLineId: null,
        requestedByUserId: "u-pub",
        reason: null,
      })
      await db
        .update(approvalRequests)
        .set({ createdAt: new Date("2026-06-02T10:00:00Z") })
        .where(eq(approvalRequests.id, "req-new"))

      const rows = await approvalsRepo.listForPublisher(db, "u-pub")
      expect(rows.map((r) => r.id)).toEqual(["req-new", "req-old"])
    })

    it("does not return another publisher's requests", async () => {
      await approvalsRepo.insertRequest(db, {
        id: "req-other",
        extensionId: "ext-a",
        extensionCategory: "skills",
        requestedTier: "company",
        subCat: "softDev",
        l2: null,
        productLineId: null,
        requestedByUserId: "u-other",
        reason: null,
      })
      const rows = await approvalsRepo.listForPublisher(db, "u-pub")
      expect(rows).toHaveLength(0)
    })
  })

  describe("listPendingForUser", () => {
    // Fixtures: three requests on two extensions; one decided so it never
    // belongs in the queue regardless of admin coverage.
    beforeEach(async () => {
      await approvalsRepo.insertRequest(db, {
        id: "req-pl-softDev",
        extensionId: "ext-a",
        extensionCategory: "skills",
        requestedTier: "productLine",
        subCat: "softDev",
        l2: "backend",
        productLineId: "wireless",
        requestedByUserId: "u-pub",
        reason: null,
      })
      await approvalsRepo.insertRequest(db, {
        id: "req-co-docs",
        extensionId: "ext-b",
        extensionCategory: "skills",
        requestedTier: "company",
        subCat: "docs",
        l2: null,
        productLineId: null,
        requestedByUserId: "u-pub",
        reason: null,
      })
      // A decided row should NOT be returned even if its cell matches.
      await approvalsRepo.insertRequest(db, {
        id: "req-decided",
        extensionId: "ext-a",
        extensionCategory: "skills",
        requestedTier: "productLine",
        subCat: "softDev",
        l2: "backend",
        productLineId: "wireless",
        requestedByUserId: "u-pub",
        reason: null,
      })
      await approvalsRepo.applyDecision(db, "req-decided", {
        status: "approved",
        decidedByUserId: "u-rev",
        decidedAt: new Date(),
        reviewerNote: null,
      })
    })

    it("returns empty for a user with no admin rows", async () => {
      expect(await approvalsRepo.listPendingForUser(db, "u-rev")).toEqual([])
    })

    it("(productLine wireless × macro=softDev) covers the wireless-softDev request", async () => {
      await adminsRepo.insertAdmin(db, {
        id: "adm-1",
        extensionCategory: "skills",
        tier: "productLine",
        productLineId: "wireless",
        categoryLevel: "macro",
        categoryKey: "softDev",
        userId: "u-rev",
      })
      const rows = await approvalsRepo.listPendingForUser(db, "u-rev")
      expect(rows.map((r) => r.id)).toEqual(["req-pl-softDev"])
    })

    it("(company × macro=docs) covers the company-docs request", async () => {
      await adminsRepo.insertAdmin(db, {
        id: "adm-1",
        extensionCategory: "skills",
        tier: "company",
        productLineId: null,
        categoryLevel: "macro",
        categoryKey: "docs",
        userId: "u-rev",
      })
      const rows = await approvalsRepo.listPendingForUser(db, "u-rev")
      expect(rows.map((r) => r.id)).toEqual(["req-co-docs"])
    })

    it("a micro=backend admin covers the wireless-softDev request via the l2 snapshot", async () => {
      await adminsRepo.insertAdmin(db, {
        id: "adm-1",
        extensionCategory: "skills",
        tier: "productLine",
        productLineId: "wireless",
        categoryLevel: "micro",
        categoryKey: "backend",
        userId: "u-rev",
      })
      const rows = await approvalsRepo.listPendingForUser(db, "u-rev")
      expect(rows.map((r) => r.id)).toEqual(["req-pl-softDev"])
    })

    it("a micro=backend admin does NOT pick up the l2-less company-docs request", async () => {
      await adminsRepo.insertAdmin(db, {
        id: "adm-1",
        extensionCategory: "skills",
        tier: "company",
        productLineId: null,
        categoryLevel: "micro",
        categoryKey: "backend",
        userId: "u-rev",
      })
      const rows = await approvalsRepo.listPendingForUser(db, "u-rev")
      expect(rows).toHaveLength(0)
    })

    it("DISTINCT de-dupes when a user holds multiple cells covering the same request", async () => {
      // Two admin rows both cover req-pl-softDev: the macro=softDev cell
      // AND the micro=backend cell. The query must not double-count.
      await adminsRepo.insertAdmin(db, {
        id: "adm-1",
        extensionCategory: "skills",
        tier: "productLine",
        productLineId: "wireless",
        categoryLevel: "macro",
        categoryKey: "softDev",
        userId: "u-rev",
      })
      await adminsRepo.insertAdmin(db, {
        id: "adm-2",
        extensionCategory: "skills",
        tier: "productLine",
        productLineId: "wireless",
        categoryLevel: "micro",
        categoryKey: "backend",
        userId: "u-rev",
      })
      const rows = await approvalsRepo.listPendingForUser(db, "u-rev")
      expect(rows.map((r) => r.id)).toEqual(["req-pl-softDev"])
    })

    it("does NOT leak a productLine request to a company-tier admin in the same subCat", async () => {
      await adminsRepo.insertAdmin(db, {
        id: "adm-1",
        extensionCategory: "skills",
        tier: "company",
        productLineId: null,
        categoryLevel: "macro",
        categoryKey: "softDev",
        userId: "u-rev",
      })
      const rows = await approvalsRepo.listPendingForUser(db, "u-rev")
      // Cover does NOT widen company → product line for routing.
      expect(rows.map((r) => r.id)).not.toContain("req-pl-softDev")
    })

    it("treats different product lines as distinct (wireless admin doesn't see datacom requests)", async () => {
      await adminsRepo.insertAdmin(db, {
        id: "adm-1",
        extensionCategory: "skills",
        tier: "productLine",
        productLineId: "datacom",
        categoryLevel: "macro",
        categoryKey: "softDev",
        userId: "u-rev",
      })
      const rows = await approvalsRepo.listPendingForUser(db, "u-rev")
      expect(rows).toHaveLength(0)
    })

    it("does NOT cross extensionCategory boundaries", async () => {
      await adminsRepo.insertAdmin(db, {
        id: "adm-1",
        extensionCategory: "mcp",
        tier: "productLine",
        productLineId: "wireless",
        categoryLevel: "all",
        categoryKey: "*",
        userId: "u-rev",
      })
      const rows = await approvalsRepo.listPendingForUser(db, "u-rev")
      expect(rows).toHaveLength(0)
    })
  })

  describe("listAllPending", () => {
    it("returns every pending request, regardless of admin coverage", async () => {
      await approvalsRepo.insertRequest(db, {
        id: "req-1",
        extensionId: "ext-a",
        extensionCategory: "skills",
        requestedTier: "productLine",
        subCat: "softDev",
        l2: "backend",
        productLineId: "wireless",
        requestedByUserId: "u-pub",
        reason: null,
      })
      await approvalsRepo.insertRequest(db, {
        id: "req-2",
        extensionId: "ext-b",
        extensionCategory: "skills",
        requestedTier: "company",
        subCat: "docs",
        l2: null,
        productLineId: null,
        requestedByUserId: "u-pub",
        reason: null,
      })
      const rows = await approvalsRepo.listAllPending(db)
      expect(rows.map((r) => r.id).sort()).toEqual(["req-1", "req-2"])
    })

    it("excludes decided requests", async () => {
      await approvalsRepo.insertRequest(db, {
        id: "req-1",
        extensionId: "ext-a",
        extensionCategory: "skills",
        requestedTier: "company",
        subCat: "softDev",
        l2: null,
        productLineId: null,
        requestedByUserId: "u-pub",
        reason: null,
      })
      await approvalsRepo.applyDecision(db, "req-1", {
        status: "approved",
        decidedByUserId: "u-rev",
        decidedAt: new Date(),
        reviewerNote: null,
      })
      expect(await approvalsRepo.listAllPending(db)).toHaveLength(0)
    })
  })

  describe("applyDecision", () => {
    it("flips a pending request to approved with the patch fields", async () => {
      await approvalsRepo.insertRequest(db, {
        id: "req-1",
        extensionId: "ext-a",
        extensionCategory: "skills",
        requestedTier: "company",
        subCat: "softDev",
        l2: null,
        productLineId: null,
        requestedByUserId: "u-pub",
        reason: null,
      })
      const decidedAt = new Date("2026-06-07T12:00:00Z")
      await approvalsRepo.applyDecision(db, "req-1", {
        status: "approved",
        decidedByUserId: "u-rev",
        decidedAt,
        reviewerNote: null,
      })
      const after = await approvalsRepo.findById(db, "req-1")
      expect(after?.status).toBe("approved")
      expect(after?.decidedByUserId).toBe("u-rev")
      expect(after?.decidedAt?.toISOString()).toBe(decidedAt.toISOString())
    })

    it("stores a reviewer note on reject", async () => {
      await approvalsRepo.insertRequest(db, {
        id: "req-1",
        extensionId: "ext-a",
        extensionCategory: "skills",
        requestedTier: "company",
        subCat: "softDev",
        l2: null,
        productLineId: null,
        requestedByUserId: "u-pub",
        reason: null,
      })
      await approvalsRepo.applyDecision(db, "req-1", {
        status: "rejected",
        decidedByUserId: "u-rev",
        decidedAt: new Date(),
        reviewerNote: "Needs a maintainer.",
      })
      const after = await approvalsRepo.findById(db, "req-1")
      expect(after?.status).toBe("rejected")
      expect(after?.reviewerNote).toBe("Needs a maintainer.")
    })

    it("returns 0 affected rows when the request is no longer pending (race lost)", async () => {
      await approvalsRepo.insertRequest(db, {
        id: "req-1",
        extensionId: "ext-a",
        extensionCategory: "skills",
        requestedTier: "company",
        subCat: "softDev",
        l2: null,
        productLineId: null,
        requestedByUserId: "u-pub",
        reason: null,
      })
      // First reviewer's UPDATE lands the decision.
      const first = await approvalsRepo.applyDecision(db, "req-1", {
        status: "approved",
        decidedByUserId: "u-rev",
        decidedAt: new Date(),
        reviewerNote: null,
      })
      expect(first).toBe(1)

      // Second reviewer's UPDATE filters out — the WHERE clause requires
      // status='pending' and the row is now approved.
      const second = await approvalsRepo.applyDecision(db, "req-1", {
        status: "rejected",
        decidedByUserId: "u-other-rev",
        decidedAt: new Date(),
        reviewerNote: null,
      })
      expect(second).toBe(0)

      const after = await approvalsRepo.findById(db, "req-1")
      expect(after?.status).toBe("approved")
      expect(after?.decidedByUserId).toBe("u-rev")
    })
  })

  describe("applyWithdraw", () => {
    it("flips a pending request to withdrawn", async () => {
      await approvalsRepo.insertRequest(db, {
        id: "req-1",
        extensionId: "ext-a",
        extensionCategory: "skills",
        requestedTier: "productLine",
        subCat: "softDev",
        l2: "backend",
        productLineId: "wireless",
        requestedByUserId: "u-pub",
        reason: null,
      })
      const at = new Date("2026-06-07T12:00:00Z")
      const affected = await approvalsRepo.applyWithdraw(db, "req-1", at)
      expect(affected).toBe(1)
      const after = await approvalsRepo.findById(db, "req-1")
      expect(after?.status).toBe("withdrawn")
      expect(after?.decidedAt?.toISOString()).toBe(at.toISOString())
      expect(after?.decidedByUserId).toBeNull()
    })

    it("returns 0 affected rows for a request that's already decided", async () => {
      await approvalsRepo.insertRequest(db, {
        id: "req-1",
        extensionId: "ext-a",
        extensionCategory: "skills",
        requestedTier: "productLine",
        subCat: "softDev",
        l2: "backend",
        productLineId: "wireless",
        requestedByUserId: "u-pub",
        reason: null,
      })
      await approvalsRepo.applyDecision(db, "req-1", {
        status: "approved",
        decidedByUserId: "u-rev",
        decidedAt: new Date(),
        reviewerNote: null,
      })
      const affected = await approvalsRepo.applyWithdraw(
        db,
        "req-1",
        new Date(),
      )
      expect(affected).toBe(0)
    })
  })

  describe("setExtensionOfficialTier + findTiersForExtensions", () => {
    it("stamps the tier on the extension", async () => {
      await approvalsRepo.setExtensionOfficialTier(db, "ext-a", "company", null)
      const [row] = await db
        .select({ officialTier: extensions.officialTier })
        .from(extensions)
        .where(eq(extensions.id, "ext-a"))
      expect(row?.officialTier).toBe("company")
    })

    it("stamps tier + productLineId together for the productLine tier", async () => {
      await approvalsRepo.setExtensionOfficialTier(
        db,
        "ext-a",
        "productLine",
        "wireless",
      )
      const [row] = await db
        .select({
          officialTier: extensions.officialTier,
          productLineId: extensions.productLineId,
        })
        .from(extensions)
        .where(eq(extensions.id, "ext-a"))
      expect(row?.officialTier).toBe("productLine")
      expect(row?.productLineId).toBe("wireless")
    })

    it("returns a map of ext id → tier or null", async () => {
      await approvalsRepo.setExtensionOfficialTier(
        db,
        "ext-a",
        "productLine",
        "wireless",
      )
      const map = await approvalsRepo.findTiersForExtensions(db, [
        "ext-a",
        "ext-b",
      ])
      expect(map.get("ext-a")).toBe("productLine")
      expect(map.get("ext-b")).toBeNull()
    })

    it("returns an empty map for an empty input", async () => {
      const map = await approvalsRepo.findTiersForExtensions(db, [])
      expect(map.size).toBe(0)
    })

    it("clears any prior revocation audit fields when re-stamping a tier", async () => {
      // Simulate the cycle: extension was revoked, then publisher re-applied
      // and a reviewer approves. The next setExtensionOfficialTier call must
      // clear the revocation trio so the publisher dashboard's annotation
      // disappears automatically.
      const revokedAt = new Date("2026-06-09T10:00:00Z")
      await db
        .update(extensions)
        .set({
          revokedAt,
          revokedByUserId: "u-rev",
          revocationNote: "policy violation",
        })
        .where(eq(extensions.id, "ext-a"))

      await approvalsRepo.setExtensionOfficialTier(db, "ext-a", "company", null)

      const [row] = await db
        .select({
          officialTier: extensions.officialTier,
          revokedAt: extensions.revokedAt,
          revokedByUserId: extensions.revokedByUserId,
          revocationNote: extensions.revocationNote,
        })
        .from(extensions)
        .where(eq(extensions.id, "ext-a"))
      expect(row?.officialTier).toBe("company")
      expect(row?.revokedAt).toBeNull()
      expect(row?.revokedByUserId).toBeNull()
      expect(row?.revocationNote).toBeNull()
    })
  })

  describe("applyRevocation", () => {
    it("clears tier + productLineId and writes the audit trio", async () => {
      await approvalsRepo.setExtensionOfficialTier(
        db,
        "ext-a",
        "productLine",
        "wireless",
      )
      const revokedAt = new Date("2026-06-09T12:00:00Z")
      const affected = await approvalsRepo.applyRevocation(db, "ext-a", {
        revokedAt,
        revokedByUserId: "u-rev",
        revocationNote: "approved by mistake",
      })
      expect(affected).toBe(1)

      const [row] = await db
        .select({
          officialTier: extensions.officialTier,
          productLineId: extensions.productLineId,
          revokedAt: extensions.revokedAt,
          revokedByUserId: extensions.revokedByUserId,
          revocationNote: extensions.revocationNote,
        })
        .from(extensions)
        .where(eq(extensions.id, "ext-a"))
      expect(row?.officialTier).toBeNull()
      expect(row?.productLineId).toBeNull()
      expect(row?.revokedAt?.toISOString()).toBe(revokedAt.toISOString())
      expect(row?.revokedByUserId).toBe("u-rev")
      expect(row?.revocationNote).toBe("approved by mistake")
    })

    it("returns 0 affected rows when the extension is already Unofficial (race lost)", async () => {
      // Extension starts Unofficial — no tier was ever set in beforeEach.
      const affected = await approvalsRepo.applyRevocation(db, "ext-a", {
        revokedAt: new Date(),
        revokedByUserId: "u-rev",
        revocationNote: "redundant",
      })
      expect(affected).toBe(0)
    })
  })
})

