      requestedByUserId: "u-other",
      status: "pending",
    })
    const rows = await getRequestsForUser("u-pub")
    expect(rows).toHaveLength(0)
  })

  it("returns empty for a user with no requests", async () => {
    const rows = await getRequestsForUser("u-pub")
    expect(rows).toEqual([])
  })
})

